div.script:
(function () {
  var spinnerSymbols = ['⣾', '⣽', '⣻', '⢿', '⡿', '⣟', '⣯', '⣷'];
  var spinnerIndex = 0;
  var spinner = document.getElementById('spinner');

  var spinnerInterval = setInterval(function () {
    spinner.textContent = spinnerSymbols[spinnerIndex];
    spinnerIndex = (spinnerIndex + 1) % spinnerSymbols.length;
  }, 120);

  function typeText(element, text, speed, done) {
    var i = 0;
    function step() {
      if (i < text.length) {
        element.textContent += text.charAt(i);
        i += 1;
        setTimeout(step, speed);
      } else if (done) {
        done();
      }
    }
    step();
  }

  var command = document.getElementById('command');
  var commandCursor = document.getElementById('commandCursor');

  typeText(command, 'whoami', 85, function () {
    commandCursor.style.display = 'none';

    setTimeout(function () {
      var line1Wrap = document.getElementById('outputLine1');
      var line1 = document.getElementById('line1');
      line1Wrap.style.display = 'flex';
      line1.innerHTML = '<span class="highlight">José Arbeláez</span> – Data Science &amp; Engineering';

      setTimeout(function () {
        var line2Wrap = document.getElementById('outputLine2');
        var line2 = document.getElementById('line2');
        var cursor2 = document.getElementById('cursor2');
        line2Wrap.style.display = 'flex';
        cursor2.style.display = 'inline-block';

        typeText(line2, 'Building • Shipping AI Agents workflows', 38, function () {
          cursor2.style.display = 'none';

          setTimeout(function () {
            var line3Wrap = document.getElementById('outputLine3');
            var line3 = document.getElementById('line3');
            line3Wrap.style.display = 'flex';
            line3.innerHTML = 'Watch: <a href="https://www.josearbelaez.com/es/" target="_blank" class="link highlight">https://www.josearbelaez.com/es/</a>';

            setTimeout(function () {
              clearInterval(spinnerInterval);
              spinner.textContent = '✓';
            }, 450);
          }, 260);
        });
      }, 350);
    }, 250);
  });
})();
